-- 1. Create the books table
CREATE TABLE IF NOT EXISTS books (
  id bigint PRIMARY KEY GENERATED BY DEFAULT AS IDENTITY,
  title text NOT NULL,
  author text NOT NULL,
  status text NOT NULL DEFAULT 'want',
  icon text NOT NULL DEFAULT '📚',
  theme text NOT NULL DEFAULT 'theme-wine',
  genres text[] NOT NULL DEFAULT '{}',
  tags text[] NOT NULL DEFAULT '{}',
  note text,
  pages integer NOT NULL DEFAULT 100,
  similar text[] NOT NULL DEFAULT '{}',
  custom_cover text,
  current_page integer NOT NULL DEFAULT 0,
  is_hidden boolean NOT NULL DEFAULT false,
  is_deleted boolean NOT NULL DEFAULT false,
  created_at timestamp with time zone DEFAULT timezone('utc'::text, now()) NOT NULL
);

-- Enable Row Level Security (RLS)
ALTER TABLE books ENABLE ROW LEVEL SECURITY;

-- Create policies for public access (anonymous access for reading/writing/deleting/updating)
-- Note: In a production environment, you might restrict these using Supabase Auth,
-- but since this is a private passcode-protected site, we will configure simple public access policies.
CREATE POLICY "Enable read access for all users" ON books FOR SELECT USING (true);
CREATE POLICY "Enable insert access for all users" ON books FOR INSERT WITH CHECK (true);
CREATE POLICY "Enable update access for all users" ON books FOR UPDATE USING (true);
CREATE POLICY "Enable delete access for all users" ON books FOR DELETE USING (true);

-- 2. Insert all 38 default books

-- Adjust the sequence value to restart at 39
SELECT setval(pg_get_serial_sequence('books', 'id'), coalesce(max(id), 0) + 1, false) FROM books;
